// Downloads section — lists the CSV files generated by the research assistant (persisted on the
// server until deleted). Newest first. Rename is inline; delete goes through the confirm popup.
(function () {
  const $ = s => document.querySelector(s);
  const list = $("#dl-list"), empty = $("#dl-empty"), count = $("#dl-count");
  const esc = s => (s || "").replace(/[&<>"]/g, c => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;" }[c]));
  const fmtSize = b => b >= 1e6 ? (b / 1e6).toFixed(1) + " MB" : b >= 1e3 ? (b / 1e3).toFixed(1) + " KB" : (b || 0) + " B";
  const fmtDate = iso => {
    const d = new Date(iso);
    return isNaN(d) ? "" : d.toLocaleString(undefined, { year: "numeric", month: "short", day: "numeric", hour: "numeric", minute: "2-digit" });
  };

  // ── confirmation popup (delete confirm + error alerts) ─────────────────────
  const dlg = $("#confirm"), cMsg = $("#confirm-msg"), cOk = $("#confirm-ok"), cCancel = $("#confirm-cancel");
  let resolveDlg = null;
  function popup(message, { danger = true, cancel = true } = {}) {
    cMsg.textContent = message;
    cOk.textContent = danger ? "Delete" : "OK";
    cOk.classList.toggle("danger", danger);
    cCancel.style.display = cancel ? "" : "none";
    dlg.hidden = false;
    return new Promise(res => { resolveDlg = res; });
  }
  function closeDlg(val) { dlg.hidden = true; const r = resolveDlg; resolveDlg = null; if (r) r(val); }
  cOk.onclick = () => closeDlg(true);
  cCancel.onclick = () => closeDlg(false);
  dlg.onclick = e => { if (e.target === dlg) closeDlg(false); };
  document.addEventListener("keydown", e => { if (e.key === "Escape" && !dlg.hidden) closeDlg(false); });
  const alertBox = msg => popup(msg, { danger: false, cancel: false });

  function row(f) {
    const el = document.createElement("div");
    el.className = "dl-row";
    el.innerHTML = `
      <div class="dl-main">
        <a class="dl-name" href="/api/downloads/${f.id}/file" title="Download">${esc(f.name)}</a>
        <span class="dl-meta">${fmtDate(f.created)} · ${(f.rows ?? 0).toLocaleString()} rows · ${fmtSize(f.size)}</span>
      </div>
      <div class="dl-actions">
        <a class="dl-btn" href="/api/downloads/${f.id}/file" title="Download" aria-label="Download ${esc(f.name)}">⤓</a>
        <button class="dl-btn dl-rename" title="Rename" aria-label="Rename ${esc(f.name)}">✎</button>
        <button class="dl-btn dl-del" title="Delete" aria-label="Delete ${esc(f.name)}">🗑</button>
      </div>`;
    el.querySelector(".dl-rename").onclick = () => rename(el, f);
    el.querySelector(".dl-del").onclick = async () => {
      if (!await popup(`Delete “${f.name}”? This can't be undone.`)) return;
      const r = await fetch(`/api/downloads/${f.id}`, { method: "DELETE" });
      if (r.ok) refresh();
      else alertBox((await r.json().catch(() => ({}))).error || "Couldn't delete the file.");
    };
    return el;
  }

  function rename(el, f) {
    const main = el.querySelector(".dl-main"), actions = el.querySelector(".dl-actions");
    main.innerHTML = ""; actions.innerHTML = "";
    const input = document.createElement("input");
    input.className = "dl-edit"; input.value = f.name; input.maxLength = 80;
    input.setAttribute("aria-label", "File name");
    main.appendChild(input);
    const save = document.createElement("button"), cancel = document.createElement("button");
    save.className = "dl-btn"; save.textContent = "✓"; save.title = "Save name";
    cancel.className = "dl-btn"; cancel.textContent = "✕"; cancel.title = "Cancel";
    actions.append(save, cancel);
    input.focus(); input.select();
    cancel.onclick = refresh;
    save.onclick = async () => {
      const r = await fetch(`/api/downloads/${f.id}`, {
        method: "PATCH", headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name: input.value })
      });
      if (r.ok) refresh();
      else alertBox((await r.json().catch(() => ({}))).error || "Rename failed.");
    };
    input.onkeydown = e => {
      if (e.key === "Enter") save.click();
      if (e.key === "Escape") cancel.click();
    };
  }

  async function refresh() {
    let files = [];
    try { files = (await (await fetch("/api/downloads")).json()).files || []; } catch (e) {}
    count.textContent = files.length ? `· ${files.length} file${files.length === 1 ? "" : "s"}` : "";
    empty.hidden = files.length > 0;
    list.innerHTML = "";
    files.forEach(f => list.appendChild(row(f)));
  }

  window.refreshDownloads = refresh;   // chat.js calls this after the assistant creates a file
  refresh();
})();
